+/* ═══════════════════════════════════════
+   Drive Hive — Cars (Admin) Styles
+   Design system: #E53935 primary, Poppins/Inter
+   ═══════════════════════════════════════ */
+
+@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=Poppins:wght@400;500;600;700&display=swap');
+
+/* ── Reset ── */
+* {
+  margin: 0;
+  padding: 0;
+  box-sizing: border-box;
+  font-family: 'Inter', 'Poppins', sans-serif;
+}
+
+body {
+  display: flex;
+  min-height: 100vh;
+  background: #F3F4F6;
+}
+
+.background {
+  position: fixed;
+  top: 0;
+  left: 0;
+  width: 100%;
+  height: 100%;
+  background: url('bg3.jpg') no-repeat center center/cover;
+  z-index: -2;
+  opacity: 0.15;
+}
+
+/* ── Sidebar ── */
+.sidebar {
+  width: 260px;
+  height: calc(100vh - 32px);
+  position: fixed;
+  left: 16px;
+  top: 16px;
+  background: #fff;
+  border-radius: 24px;
+  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.08);
+  display: flex;
+  flex-direction: column;
+  align-items: center;
+  padding: 24px 16px;
+  z-index: 100;
+  border: 1px solid #E5E7EB;
+  transition: all 0.3s ease;
+}
+
+.logo {
+  width: 64px;
+  height: 64px;
+  margin-bottom: 8px;
+  border-radius: 16px;
+  object-fit: contain;
+}
+
+.sidebar-title {
+  font-family: 'Poppins', sans-serif;
+  font-size: 1.15rem;
+  font-weight: 700;
+  color: #222;
+  margin-bottom: 24px;
+  letter-spacing: -0.3px;
+}
+
+.nav-links {
+  list-style: none;
+  padding: 0;
+  width: 100%;
+  flex: 1;
+  overflow-y: auto;
+  display: flex;
+  flex-direction: column;
+  gap: 2px;
+}
+
+.nav-item {
+  display: flex;
+  align-items: center;
+  gap: 12px;
+  padding: 10px 16px;
+  font-size: 0.9rem;
+  font-weight: 500;
+  color: #6B7280;
+  border-radius: 12px;
+  cursor: pointer;
+  transition: all 0.15s ease;
+  white-space: nowrap;
+}
+
+.nav-item i {
+  width: 20px;
+  text-align: center;
+  font-size: 1.05rem;
+}
+
+.nav-item:hover {
+  background: #F0F2F5;
+  color: #222;
+  transform: translateX(2px);
+}
+
+.nav-item.active {
+  background: #FFEBEE;
+  color: #E53935;
+  font-weight: 600;
+  box-shadow: inset 3px 0 0 #E53935;
+}
+
+/* ── Logout ── */
+.logout-btn {
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  gap: 8px;
+  width: 100%;
+  padding: 10px 16px;
+  margin-top: 12px;
+  background: transparent;
+  color: #6B7280;
+  border: 1.5px solid #E5E7EB;
+  border-radius: 12px;
+  font-size: 0.85rem;
+  font-weight: 500;
+  cursor: pointer;
+  transition: all 0.15s ease;
+}
+
+.logout-btn:hover {
+  background: #FFEBEE;
+  color: #E53935;
+  border-color: #E53935;
+}
+
+/* ── Main Content ── */
+.main-content {
+  margin-left: 292px;
+  padding: 32px;
+  width: calc(100% - 292px);
+  min-height: 100vh;
+  background: #fff;
+  border-radius: 24px 24px 0 0;
+  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.04);
+  overflow-y: auto;
+  transition: margin-left 0.3s ease, width 0.3s ease;
+}
+
+.main-content h1 {
+  font-family: 'Poppins', sans-serif;
+  font-size: 1.75rem;
+  font-weight: 700;
+  color: #222;
+  margin-bottom: 8px;
+}
+
+/* ── Top Bar ── */
+.top-bar {
+  display: flex;
+  justify-content: space-between;
+  align-items: center;
+  margin-bottom: 24px;
+  gap: 16px;
+  flex-wrap: wrap;
+}
+
+.top-bar button {
+  background: #E53935;
+  color: #fff;
+  border: none;
+  padding: 10px 20px;
+  border-radius: 12px;
+  cursor: pointer;
+  font-weight: 500;
+  font-size: 0.9rem;
+  display: flex;
+  align-items: center;
+  gap: 8px;
+  transition: all 0.15s ease;
+}
+
+.top-bar button:hover {
+  background: #C62828;
+  box-shadow: 0 4px 12px rgba(229, 57, 53, 0.3);
+}
+
+#filterBtn {
+  background: #F0F2F5;
+  color: #333;
+}
+
+#filterBtn:hover {
+  background: #E5E7EB;
+  box-shadow: none;
+}
+
+/* ── Cars Grid ── */
+.cars-grid {
+  display: grid;
+  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
+  gap: 24px;
+  padding: 0;
+  width: 100%;
+}
+
+/* ── Car Card ── */
+.car-card {
+  background: #fff;
+  border-radius: 16px;
+  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.04), 0 8px 24px rgba(0, 0, 0, 0.05);
+  border: 1px solid #E5E7EB;
+  overflow: hidden;
+  display: flex;
+  flex-direction: column;
+  transition: all 0.3s ease;
+}
+
+.car-card:hover {
+  transform: translateY(-6px);
+  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.1);
+}
+
+.car-image {
+  width: 100%;
+  height: 180px;
+  object-fit: cover;
+  display: block;
+}
+
+.car-card h3 {
+  font-family: 'Poppins', sans-serif;
+  font-size: 1.1rem;
+  font-weight: 600;
+  color: #222;
+  padding: 12px 16px 4px;
+}
+
+.car-card p {
+  padding: 2px 16px;
+  font-size: 0.85rem;
+  color: #555;
+  line-height: 1.5;
+}
+
+.car-card p strong {
+  color: #333;
+  font-weight: 600;
+}
+
+/* ── Car Description ── */
+.car-description {
+  max-height: 48px;
+  overflow: hidden;
+  text-overflow: ellipsis;
+  display: -webkit-box;
+  -webkit-line-clamp: 2;
+  -webkit-box-orient: vertical;
+  font-size: 0.83rem;
+  color: #777;
+  padding: 2px 16px;
+}
+
+/* ── Status Badges ── */
+.car-status {
+  display: inline-block;
+  padding: 4px 12px;
+  border-radius: 20px;
+  font-size: 0.75rem;
+  font-weight: 600;
+  text-transform: uppercase;
+  letter-spacing: 0.3px;
+}
+
+.car-status.available,
+.status-available {
+  background: #E8F5E9;
+  color: #2E7D32;
+}
+
+.car-status.disabled,
+.status-disabled {
+  background: #FFEBEE;
+  color: #C62828;
+}
+
+/* ── Disabled Car Overlay ── */
+.disabled-car {
+  background: #F8F8F8;
+  opacity: 0.6;
+  pointer-events: auto;
+}
+
+.disabled-car .car-image {
+  filter: grayscale(100%);
+}
+
+/* ── Car Buttons ── */
+.car-buttons {
+  display: flex;
+  justify-content: center;
+  gap: 10px;
+  padding: 12px 16px 16px;
+  margin-top: auto;
+}
+
+.car-buttons button {
+  border: none;
+  padding: 8px 16px;
+  cursor: pointer;
+  border-radius: 10px;
+  font-weight: 600;
+  font-size: 0.82rem;
+  transition: all 0.2s ease;
+}
+
+/* Edit Button */
+.edit-btn {
+  background: #E53935;
+  color: #fff;
+}
+
+.edit-btn:hover {
+  background: #C62828;
+  box-shadow: 0 4px 12px rgba(229, 57, 53, 0.3);
+}
+
+/* Disable Button */
+.disable-btn {
+  background: #EF5350;
+  color: #fff;
+}
+
+.disable-btn:hover {
+  background: #E53935;
+  box-shadow: 0 4px 12px rgba(229, 57, 53, 0.25);
+}
+
+/* Enable Button */
+.enable-btn {
+  background: #43A047;
+  color: #fff;
+}
+
+.enable-btn:hover {
+  background: #388E3C;
+  box-shadow: 0 4px 12px rgba(67, 160, 71, 0.3);
+}
+
+/* ── Generic Buttons ── */
+.buttons {
+  display: flex;
+  gap: 10px;
+}
+
+button {
+  background-color: #E53935;
+  color: #fff;
+  padding: 10px 20px;
+  border: none;
+  cursor: pointer;
+  border-radius: 10px;
+  display: flex;
+  align-items: center;
+  gap: 6px;
+  font-size: 0.9rem;
+  font-weight: 500;
+  transition: all 0.15s ease;
+}
+
+button i {
+  font-size: 1rem;
+}
+
+button:hover {
+  background: #C62828;
+  box-shadow: 0 4px 12px rgba(229, 57, 53, 0.25);
+}
+
+/* ── Modal ── */
+.modal {
+  display: none;
+  position: fixed;
+  top: 0;
+  left: 0;
+  width: 100%;
+  height: 100%;
+  background: rgba(0, 0, 0, 0.5);
+  justify-content: center;
+  align-items: center;
+  z-index: 1000;
+  overflow: auto;
+  backdrop-filter: blur(4px);
+}
+
+.modal-content {
+  background: #fff;
+  padding: 28px;
+  border-radius: 20px;
+  width: 520px;
+  max-width: 95vw;
+  box-shadow: 0 16px 48px rgba(0, 0, 0, 0.18);
+  text-align: left;
+  position: relative;
+  animation: fadeIn 0.3s ease-in-out;
+  max-height: 90vh;
+  overflow-y: auto;
+}
+
+@keyframes fadeIn {
+  from { opacity: 0; transform: translateY(-10px); }
+  to   { opacity: 1; transform: translateY(0); }
+}
+
+.modal .close {
+  position: absolute;
+  top: 16px;
+  right: 18px;
+  font-size: 24px;
+  cursor: pointer;
+  color: #999;
+  transition: color 0.15s ease;
+  line-height: 1;
+}
+
+.modal .close:hover {
+  color: #E53935;
+}
+
+.modal h2 {
+  font-family: 'Poppins', sans-serif;
+  font-size: 1.35rem;
+  font-weight: 700;
+  color: #222;
+  margin-bottom: 20px;
+}
+
+/* ── Form Styles ── */
+#carForm {
+  display: grid;
+  grid-template-columns: 1fr 1fr;
+  gap: 16px;
+}
+
+#carForm label {
+  display: block;
+  margin-bottom: 4px;
+  font-size: 0.82rem;
+  font-weight: 600;
+  color: #444;
+}
+
+#carForm input,
+#carForm textarea,
+#carForm select {
+  width: 100%;
+  padding: 10px 14px;
+  border: 1.5px solid #E5E7EB;
+  border-radius: 10px;
+  font-size: 0.9rem;
+  font-family: 'Inter', sans-serif;
+  transition: all 0.15s ease;
+  background: #FAFAFA;
+}
+
+#carForm input:focus,
+#carForm textarea:focus,
+#carForm select:focus {
+  outline: none;
+  border-color: #E53935;
+  box-shadow: 0 0 0 3px rgba(229, 57, 53, 0.08);
+  background: #fff;
+}
+
+#carForm textarea {
+  resize: vertical;
+  min-height: 80px;
+}
+
+#carForm button[type="submit"] {
+  grid-column: span 2;
+  padding: 12px;
+  background: #E53935;
+  color: #fff;
+  border: none;
+  border-radius: 12px;
+  cursor: pointer;
+  font-size: 1rem;
+  font-weight: 600;
+  transition: all 0.2s ease;
+}
+
+#carForm button[type="submit"]:hover {
+  background: #C62828;
+  box-shadow: 0 4px 16px rgba(229, 57, 53, 0.35);
+}
+
+/* ── Form Group ── */
+.form-group {
+  display: flex;
+  flex-direction: column;
+}
+
+.form-group label {
+  font-weight: 600;
+  font-size: 0.82rem;
+  color: #444;
+  margin-bottom: 4px;
+}
+
+.form-group input,
+.form-group textarea,
+.form-group select {
+  padding: 10px 14px;
+  border: 1.5px solid #E5E7EB;
+  border-radius: 10px;
+  font-size: 0.9rem;
+  background: #FAFAFA;
+  transition: all 0.15s ease;
+}
+
+.form-group input:focus,
+.form-group textarea:focus,
+.form-group select:focus {
+  outline: none;
+  border-color: #E53935;
+  box-shadow: 0 0 0 3px rgba(229, 57, 53, 0.08);
+  background: #fff;
+}
+
+/* Legacy form selectors preserved */
+form label {
+  font-weight: 600;
+  display: block;
+  margin-top: 10px;
+  font-size: 0.82rem;
+  color: #444;
+}
+
+form input,
+form textarea {
+  width: 100%;
+  padding: 10px 14px;
+  border: 1.5px solid #E5E7EB;
+  border-radius: 10px;
+  font-size: 0.9rem;
+  background: #FAFAFA;
+  margin-bottom: 4px;
+  transition: all 0.15s ease;
+}
+
+form input:focus,
+form textarea:focus {
+  outline: none;
+  border-color: #E53935;
+  box-shadow: 0 0 0 3px rgba(229, 57, 53, 0.08);
+  background: #fff;
+}
+
+form textarea {
+  resize: vertical;
+}
+
+form button {
+  width: 100%;
+  padding: 12px;
+  margin-top: 15px;
+  border: none;
+  background: #E53935;
+  color: #fff;
+  font-size: 1rem;
+  font-weight: 600;
+  border-radius: 12px;
+  cursor: pointer;
+  transition: all 0.2s ease;
+}
+
+form button:hover {
+  background: #C62828;
+  box-shadow: 0 4px 16px rgba(229, 57, 53, 0.35);
+}
+
+/* ── Image Upload Section ── */
+.image-upload-section {
+  grid-column: span 2;
+}
+
+.image-upload-section label {
+  display: block;
+  font-weight: 600;
+  font-size: 0.82rem;
+  color: #444;
+  margin-bottom: 6px;
+}
+
+#previewImage,
+.image-preview {
+  max-width: 200px;
+  max-height: 150px;
+  width: auto;
+  height: auto;
+  display: block;
+  margin-top: 10px;
+  border: 1.5px solid #E5E7EB;
+  border-radius: 10px;
+  object-fit: cover;
+}
+
+.reference-preview {
+  max-width: 200px;
+  max-height: 150px;
+  width: auto;
+  height: auto;
+  display: block;
+  margin-top: 10px;
+  border: 1.5px solid #E5E7EB;
+  border-radius: 10px;
+  object-fit: cover;
+}
+
+.image-source-label {
+  display: block;
