+
+/* ── Reference Images ── */
+.reference-image-item {
+  display: flex;
+  align-items: center;
+  gap: 10px;
+  padding: 10px;
+  background: #F8F9FA;
+  border-radius: 12px;
+  margin-bottom: 10px;
+  flex-wrap: wrap;
+}
+
+.reference-image-item input[type="file"] {
