/* ───────────────────────────────────────────────
   DriveHiveCutie — Admin Settings (Premium)
   ─────────────────────────────────────────────── */

/* Import Fonts */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Poppins:wght@300;400;500;600;700&display=swap');

/* ── CSS Variables ── */
:root {
    --primary: #E53935;
    --primary-dark: #C62828;
    --primary-light: #FFEBEE;
    --primary-glow: rgba(229, 57, 53, 0.25);
    --white: #FFFFFF;
    --bg: #F5F5F5;
    --text: #1E1E1E;
    --text-muted: #6B7280;
    --border: #E5E7EB;
    --shadow-sm: 0 1px 3px rgba(0, 0, 0, 0.06), 0 1px 2px rgba(0, 0, 0, 0.04);
    --shadow: 0 4px 16px rgba(0, 0, 0, 0.08);
    --shadow-lg: 0 12px 40px rgba(0, 0, 0, 0.12);
    --shadow-xl: 0 20px 60px rgba(0, 0, 0, 0.15);
    --radius: 16px;
    --radius-sm: 10px;
    --radius-xs: 8px;
    --sidebar-w: 260px;
    --transition: 0.25s cubic-bezier(0.4, 0, 0.2, 1);
}

/* ── Reset ── */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    display: flex;
    height: 100vh;
    width: 100%;
    font-family: 'Inter', 'Poppins', sans-serif;
    background: url('bg3.jpg') no-repeat center center / cover;
    background-attachment: fixed;
    overflow-x: hidden;
}

/* ── Background Overlay ── */
.background {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: inherit;
    z-index: -2;
}

.background::after {
    content: '';
    position: fixed;
    inset: 0;
    background: rgba(255, 255, 255, 0.55);
    z-index: -1;
}

/* ═══════════════════════════════════════════════
   SIDEBAR — Floating Premium
   ═══════════════════════════════════════════════ */
.sidebar {
    width: var(--sidebar-w);
    height: calc(100vh - 32px);
    background: var(--white);
    padding: 28px 20px;
    position: fixed;
    left: 16px;
    top: 16px;
    display: flex;
    flex-direction: column;
    align-items: center;
    border-radius: 24px;
    box-shadow: var(--shadow-xl);
    z-index: 100;
    transition: transform var(--transition), box-shadow var(--transition);
}

.sidebar:hover {
    box-shadow: 0 24px 72px rgba(0, 0, 0, 0.18);
}

/* ── Logo ── */
.logo {
    width: 80px;
    height: auto;
    margin-bottom: 10px;
    border-radius: 50%;
    transition: transform var(--transition);
}

.logo:hover {
    transform: scale(1.08);
}

/* ── Sidebar Title ── */
.sidebar-title {
    color: var(--text);
    font-size: 20px;
    font-weight: 700;
    letter-spacing: 0.5px;
    margin-bottom: 28px;
    font-family: 'Poppins', sans-serif;
}

.sidebar-title span {
    color: var(--primary);
}

/* ── Nav Links ── */
.nav-links {
    list-style: none;
    padding: 0;
    width: 100%;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

/* ── Nav Item ── */
.nav-item {
    display: flex;
    align-items: center;
    padding: 12px 16px;
    font-size: 15px;
    font-weight: 500;
    color: var(--text-muted);
    border-radius: var(--radius-sm);
    cursor: pointer;
    transition: all var(--transition);
    border-left: 3px solid transparent;
    text-decoration: none;
    user-select: none;
}

.nav-item i {
    margin-right: 12px;
    font-size: 18px;
    width: 22px;
    text-align: center;
    transition: color var(--transition);
}

.nav-item:hover {
    background: #FAFAFA;
    color: var(--text);
    padding-left: 18px;
}

/* ── Active Nav ── */
.nav-item.active {
    background: var(--primary-light);
    border-left: 3px solid var(--primary);
    color: var(--primary);
    font-weight: 600;
    padding-left: 16px;
    box-shadow: inset 0 0 0 1px rgba(229, 57, 53, 0.10);
}

.nav-item.active i {
    color: var(--primary);
}

/* ═══════════════════════════════════════════════
   MAIN CONTENT
   ═══════════════════════════════════════════════ */
.main-content {
    margin-left: calc(var(--sidebar-w) + 32px);
    width: calc(100% - var(--sidebar-w) - 32px);
    display: flex;
    justify-content: center;
    align-items: flex-start;
    min-height: 100vh;
    padding: 24px;
    overflow-y: auto;
}

/* ═══════════════════════════════════════════════
   SETTINGS CONTAINER
   ═══════════════════════════════════════════════ */
.settings-container {
    width: 100%;
    max-width: 760px;
    padding: 36px 32px;
    background: var(--white);
    border-radius: var(--radius);
    box-shadow: var(--shadow-lg);
    margin-top: 8px;
}

/* ── Section Headings ── */
h3 {
    font-family: 'Poppins', sans-serif;
    font-size: 18px;
    font-weight: 600;
    color: var(--text);
    margin-bottom: 14px;
    letter-spacing: -0.2px;
    display: flex;
    align-items: center;
    gap: 8px;
}

h3::before {
    content: '';
    display: inline-block;
    width: 4px;
    height: 20px;
    background: var(--primary);
    border-radius: 2px;
    flex-shrink: 0;
}

/* ═══════════════════════════════════════════════
   FORM SECTIONS
   ═══════════════════════════════════════════════ */
.admin-section,
.payment-section,
.current-details-section {
    background: var(--white);
    padding: 24px;
    border-radius: var(--radius-sm);
    margin-bottom: 20px;
    border: 1px solid var(--border);
    box-shadow: var(--shadow-sm);
    transition: box-shadow var(--transition);
}

.admin-section:hover,
.payment-section:hover,
.current-details-section:hover {
    box-shadow: var(--shadow);
}

/* ── Form Group ── */
.form-group {
    margin-bottom: 18px;
}

/* ── Labels ── */
label {
    display: block;
    font-weight: 500;
    font-size: 14px;
    color: var(--text);
    margin-bottom: 6px;
    letter-spacing: 0.1px;
}

/* ═══════════════════════════════════════════════
   INPUTS
   ═══════════════════════════════════════════════ */
input {
    width: 100%;
    padding: 12px 14px;
    margin: 4px 0 2px;
    border: 1.5px solid var(--border);
    border-radius: var(--radius-xs);
    font-size: 14px;
    font-family: 'Inter', sans-serif;
    color: var(--text);
    background: #FAFBFC;
    transition: all var(--transition);
    outline: none;
}

input::placeholder {
    color: #9CA3AF;
}

input:hover {
    border-color: #D1D5DB;
}

input:focus {
    border-color: var(--primary);
    background: var(--white);
    box-shadow: 0 0 0 4px var(--primary-glow);
}

input[type="text"],
input[type="file"] {
    width: 100%;
    padding: 12px 14px;
    border: 1.5px solid var(--border);
    border-radius: var(--radius-xs);
    font-size: 14px;
    font-family: 'Inter', sans-serif;
    color: var(--text);
    background: #FAFBFC;
    transition: all var(--transition);
    outline: none;
}

input[type="text"]:hover,
input[type="file"]:hover {
    border-color: #D1D5DB;
}

input[type="text"]:focus,
input[type="file"]:focus {
    border-color: var(--primary);
    background: var(--white);
    box-shadow: 0 0 0 4px var(--primary-glow);
}

/* ── File Input Custom Styling ── */
input[type="file"] {
    padding: 10px 14px;
    cursor: pointer;
}

input[type="file"]::file-selector-button {
    padding: 8px 18px;
    margin-right: 12px;
    border: none;
    border-radius: 6px;
    background: var(--primary-light);
    color: var(--primary);
    font-weight: 600;
    font-size: 13px;
    cursor: pointer;
    transition: all var(--transition);
}

input[type="file"]::file-selector-button:hover {
    background: #FFCDD2;
}

/* ═══════════════════════════════════════════════
   BUTTONS
   ═══════════════════════════════════════════════ */
button {
    width: 100%;
    padding: 13px 20px;
    background: var(--primary);
    color: var(--white);
    border: none;
    border-radius: var(--radius-xs);
    font-size: 15px;
    font-weight: 600;
    font-family: 'Inter', 'Poppins', sans-serif;
    cursor: pointer;
    transition: all var(--transition);
    letter-spacing: 0.2px;
    position: relative;
    overflow: hidden;
}

button::after {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(135deg, rgba(255,255,255,0.15) 0%, transparent 60%);
    pointer-events: none;
}

button:hover {
    background: var(--primary-dark);
    transform: translateY(-1px);
    box-shadow: 0 6px 20px rgba(229, 57, 53, 0.35);
}

button:active {
    transform: translateY(0);
    box-shadow: 0 2px 8px rgba(229, 57, 53, 0.3);
    transition: all 0.08s ease;
}

/* ═══════════════════════════════════════════════
   MESSAGE FEEDBACK
   ═══════════════════════════════════════════════ */
#adminMessage,
#paymentMessage {
    margin-top: 10px;
    font-weight: 500;
    font-size: 14px;
    padding: 8px 0;
    border-radius: var(--radius-xs);
}

/* ═══════════════════════════════════════════════
   CURRENT DETAILS SECTION
   ═══════════════════════════════════════════════ */
.current-details-section {
    text-align: left;
}

.current-details-section p {
    margin: 10px 0;
    font-size: 14px;
    color: var(--text-muted);
    line-height: 1.6;
}

.current-details-section p strong {
    color: var(--text);
    font-weight: 600;
}

/* ── QR Code ── */
.current-details-section img {
    max-width: 100%;
    height: auto;
    border-radius: var(--radius-xs);
    margin-top: 10px;
    max-height: 180px;
    border: 1px solid var(--border);
    padding: 8px;
    background: var(--white);
    box-shadow: var(--shadow-sm);
    transition: transform var(--transition);
}

.current-details-section img:hover {
    transform: scale(1.03);
}

/* QR Code Preview (dedicated wrapper) */
.qr-code-preview img {
    max-width: 100%;
    max-height: 160px;
    border-radius: var(--radius-xs);
    margin-top: 10px;
    border: 1px solid var(--border);
    padding: 6px;
    background: var(--white);
}

/* ═══════════════════════════════════════════════
   PAYMENT DETAILS — Card Layout
   ═══════════════════════════════════════════════ */
.payment_details {
    display: flex;
    gap: 24px;
    justify-content: space-between;
    align-items: stretch;
    flex-wrap: nowrap;
}

/* ── Card ── */
.card {
    flex: 1;
    min-width: 280px;
    padding: 28px 24px;
    background: var(--white);
    border-radius: var(--radius-sm);
    box-shadow: var(--shadow-sm);
    border: 1px solid var(--border);
    transition: all var(--transition);
    display: flex;
    flex-direction: column;
}

.card:hover {
    transform: translateY(-6px);
    box-shadow: var(--shadow-lg);
    border-color: transparent;
}

.card h4 {
    font-family: 'Poppins', sans-serif;
    font-size: 16px;
    font-weight: 600;
    color: var(--text);
    margin-bottom: 16px;
}

/* ═══════════════════════════════════════════════
   RESPONSIVE — 1024px
   ═══════════════════════════════════════════════ */
@media (max-width: 1024px) {
    .sidebar {
        width: 240px;
        left: 10px;
        top: 10px;
        height: calc(100vh - 20px);
        border-radius: 20px;
        padding: 22px 16px;
    }

    .main-content {
        margin-left: calc(240px + 20px);
        width: calc(100% - 240px - 20px);
        padding: 16px;
    }

    .settings-container {
        max-width: 100%;
        padding: 28px 24px;
    }

    .payment_details {
        flex-wrap: wrap;
        gap: 16px;
    }

    .card {
        flex: 1 1 calc(50% - 8px);
        min-width: 240px;
    }
}

/* ═══════════════════════════════════════════════
   RESPONSIVE — 768px
   ═══════════════════════════════════════════════ */
@media (max-width: 768px) {
    :root {
        --sidebar-w: 0px;
    }

    .sidebar {
        width: 100%;
        height: auto;
        position: relative;
        left: 0;
        top: 0;
        border-radius: 0;
        flex-direction: row;
        flex-wrap: wrap;
        justify-content: space-between;
        padding: 14px 20px;
        box-shadow: var(--shadow);
        gap: 8px;
    }

    .logo {
        width: 44px;
        margin-bottom: 0;
    }

    .sidebar-title {
        font-size: 16px;
        margin-bottom: 0;
        order: 2;
    }

    .nav-links {
        flex-direction: row;
        flex-wrap: wrap;
        gap: 2px;
        width: 100%;
        order: 3;
        justify-content: center;
    }

    .nav-item {
        padding: 8px 12px;
        font-size: 13px;
        border-left: none;
        border-radius: var(--radius-xs);
    }

    .nav-item.active {
        border-left: none;
        border-bottom: 2px solid var(--primary);
        padding-left: 12px;
    }

    .main-content {
        margin-left: 0;
        width: 100%;
        padding: 12px;
        align-items: flex-start;
    }

    .settings-container {
        max-width: 100%;
        padding: 20px 16px;
        border-radius: var(--radius-sm);
        margin-top: 0;
    }

    h3 {
        font-size: 16px;
    }

    .admin-section,
    .payment-section,
    .current-details-section {
        padding: 16px;
        margin-bottom: 14px;
    }

    .payment_details {
        flex-direction: column;
        gap: 14px;
    }

    .card {
        flex: 1 1 100%;
        min-width: 100%;
        padding: 20px 16px;
    }

    .card:hover {
        transform: translateY(-3px);
    }

    button {
        padding: 12px 16px;
        font-size: 14px;
    }

    input,
    input[type="text"],
    input[type="file"] {
        padding: 10px 12px;
        font-size: 13px;
    }

    .current-details-section img {
        max-height: 140px;
    }
}

