input.content:
/* Import Fonts */
@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700&family=Inter:wght@300;400;500;600;700&display=swap');

/* ===== CSS VARIABLES ===== */
:root {
    --primary: #E53935;
    --primary-dark: #C62828;
    --primary-light: #FFEBEE;
    --primary-gradient: linear-gradient(135deg, #E53935, #C62828);
    --sidebar-width: 260px;
    --sidebar-collapsed: 0px;
    --bg: #F5F6FA;
    --white: #FFFFFF;
    --text: #2D3436;
    --text-muted: #636E72;
    --border: #E0E0E0;
    --shadow-sm: 0 2px 8px rgba(0, 0, 0, 0.06);
    --shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
    --shadow-lg: 0 12px 40px rgba(0, 0, 0, 0.12);
    --radius-sm: 8px;
    --radius: 12px;
    --radius-lg: 16px;
    --radius-xl: 24px;
    --transition: 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

/* ===== RESET ===== */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
    font-family: 'Poppins', 'Inter', sans-serif;
}

body {
    display: flex;
    min-height: 100vh;
    width: 100%;
    justify-content: flex-start;
    align-items: flex-start;
    background: var(--bg);
    overflow-x: hidden;
}

.background {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: linear-gradient(135deg, #f5f6fa 0%, #e8eaf6 50%, #fce4ec 100%);
    z-index: -2;
}

/* ===== SIDEBAR ===== */
.sidebar {
    width: var(--sidebar-width);
    height: 100vh;
    background: var(--white);
    padding: 28px 18px;
    position: fixed;
    left: 16px;
    top: 16px;
    bottom: 16px;
    display: flex;
    flex-direction: column;
    align-items: center;
    border-radius: var(--radius-xl);
    box-shadow: var(--shadow-lg);
    z-index: 100;
    transition: all var(--transition);
    overflow-y: auto;
}

.logo {
    width: 72px;
    height: 72px;
    margin-bottom: 8px;
    object-fit: contain;
    border-radius: 50%;
    transition: transform var(--transition);
}

.logo:hover {
    transform: scale(1.08);
}

.sidebar-title {
    color: var(--primary);
    font-size: 18px;
    font-weight: 700;
    margin-bottom: 28px;
    letter-spacing: 1px;
    text-transform: uppercase;
    text-align: center;
}

.nav-links {
    list-style: none;
    padding: 0;
    width: 100%;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.nav-item {
    display: flex;
    align-items: center;
    padding: 12px 16px;
    font-size: 14px;
    font-weight: 500;
    color: var(--text-muted);
    border-radius: var(--radius);
    cursor: pointer;
    transition: all var(--transition);
    border-left: 3px solid transparent;
    position: relative;
}

.nav-item i {
    margin-right: 12px;
    font-size: 16px;
    width: 20px;
    text-align: center;
    transition: color var(--transition);
}

.nav-item:hover {
    background: #F5F5F5;
    color: var(--text);
    border-left: 3px solid #E0E0E0;
}

.nav-item.active {
    background: var(--primary-light);
    color: var(--primary);
    border-left: 3px solid var(--primary);
    font-weight: 600;
    box-shadow: inset 0 0 0 1px rgba(229, 57, 53, 0.1);
}

.nav-item.active i {
    color: var(--primary);
}

/* ===== MAIN CONTENT ===== */
.main-content {
    margin-left: calc(var(--sidebar-width) + 32px);
    padding: 24px 32px;
    width: calc(100% - var(--sidebar-width) - 32px);
    min-height: 100vh;
    background: transparent;
    transition: margin-left var(--transition), width var(--transition);
}

/* ===== TOP BAR ===== */
.top-bar {
    display: flex;
    justify-content: flex-end;
    align-items: center;
    padding: 16px 24px;
    background: var(--white);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-sm);
    margin-bottom: 24px;
    gap: 8px;
    flex-wrap: wrap;
}

/* ===== NOTIFICATION BUTTON ===== */
.notif-btn {
    position: relative;
    background: #F5F5F5;
    border: none;
    font-size: 1.1rem;
    color: var(--text);
    cursor: pointer;
    padding: 10px 14px;
    margin-right: 4px;
    border-radius: var(--radius);
    transition: all var(--transition);
    display: flex;
    align-items: center;
    justify-content: center;
}

.notif-btn:hover {
    background: #EEEEEE;
    color: var(--primary);
}

.notification-count {
    position: absolute;
    top: -4px;
    right: -4px;
    background: var(--primary);
    color: white;
    border-radius: 50%;
    width: 20px;
    height: 20px;
    display: flex;
    justify-content: center;
    align-items: center;
    font-size: 0.65rem;
    font-weight: 700;
    box-shadow: 0 2px 6px rgba(229, 57, 53, 0.3);
}

.notification-count.hidden {
    display: none;
}

/* ===== MESSAGE BUTTON ===== */
.message-btn {
    background: #F5F5F5;
    border: none;
    color: var(--text);
    font-size: 1.1rem;
    cursor: pointer;
    position: relative;
    margin-right: 4px;
    padding: 10px 14px;
    border-radius: var(--radius);
    transition: all var(--transition);
    display: flex;
    align-items: center;
    justify-content: center;
}

.message-btn:hover {
    background: #EEEEEE;
    color: var(--primary);
}

.message-count {
    position: absolute;
    top: -4px;
    right: -4px;
    background-color: #ff4757;
    color: white;
    border-radius: 50%;
    width: 20px;
    height: 20px;
    font-size: 0.65rem;
    font-weight: 700;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 2px 6px rgba(255, 71, 87, 0.3);
}

/* ===== LOGOUT BUTTON ===== */
.logout-btn {
    background: var(--primary);
    border: none;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    margin-left: 12px;
    padding: 10px 22px;
    border-radius: var(--radius);
    color: var(--white);
    transition: all var(--transition);
    box-shadow: 0 2px 8px rgba(229, 57, 53, 0.25);
}

.logout-btn:hover {
    background: var(--primary-dark);
    box-shadow: 0 4px 16px rgba(229, 57, 53, 0.35);
    transform: translateY(-1px);
}

/* ===== STAT CARDS ===== */
.cards {
    display: flex;
    gap: 20px;
    margin-bottom: 28px;
    flex-wrap: wrap;
}

.card {
    flex: 1;
    min-width: 200px;
    background: var(--white);
    padding: 28px 24px;
    box-shadow: var(--shadow);
    text-align: center;
    border-radius: var(--radius-lg);
    transition: all var(--transition);
    cursor: default;
    position: relative;
    overflow: hidden;
}

.card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 4px;
    background: var(--primary-gradient);
    border-radius: var(--radius-lg) var(--radius-lg) 0 0;
    opacity: 0;
    transition: opacity var(--transition);
}

.card:hover {
    transform: translateY(-6px);
    box-shadow: var(--shadow-lg);
    background: var(--primary-gradient);
    color: white;
}

.card:hover::before {
    opacity: 0;
}

.card:hover h3 {
    color: rgba(255, 255, 255, 0.9);
}

.card:hover p {
    color: white;
}

.card h3 {
    font-size: 14px;
    font-weight: 600;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    margin-bottom: 12px;
    transition: color var(--transition);
}

.card p {
    font-size: 60px;
    font-weight: 700;
    color: var(--text);
    transition: color var(--transition);
    line-height: 1;
}

/* ===== TABLES SECTION ===== */
.tables {
    display: flex;
    gap: 24px;
    flex-wrap: wrap;
}

.table-container {
    flex: 1;
    min-width: 400px;
    background: var(--white);
    padding: 24px;
    box-shadow: var(--shadow);
    border-radius: var(--radius-lg);
    overflow: hidden;
    transition: box-shadow var(--transition);
}

.table-container:hover {
    box-shadow: var(--shadow-lg);
}

.table-container h3 {
    font-size: 16px;
    font-weight: 700;
    color: var(--text);
    margin-bottom: 18px;
    padding-bottom: 12px;
    border-bottom: 2px solid var(--primary-light);
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

table {
    width: 100%;
    border-collapse: collapse;
    font-size: 13px;
}

thead {
    background: #FAFAFA;
}

th {
    padding: 14px 12px;
    border-bottom: 2px solid #E0E0E0;
    text-align: center;
    font-weight: 700;
    font-size: 12px;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    white-space: nowrap;
}

td {
    padding: 14px 12px;
    border-bottom: 1px solid #F0F0F0;
    text-align: center;
    color: var(--text);
    font-weight: 400;
    transition: background var(--transition);
}

tbody tr {
    transition: all var(--transition);
}

tbody tr:hover {
    background: #FCE4EC;
}

tbody tr:hover td {
    color: var(--text);
}

/* ===== ACTION BUTTONS ===== */
.mark-active-btn {
    padding: 8px 18px;
    border: none;
    border-radius: 20px;
    cursor: pointer;
    font-size: 13px;
    font-weight: 600;
    transition: all var(--transition);
    background-color: #43A047;
    color: white;
    box-shadow: 0 2px 8px rgba(67, 160, 71, 0.25);
}

.mark-active-btn:hover {
    background-color: #388E3C;
    box-shadow: 0 4px 14px rgba(67, 160, 71, 0.4);
    transform: translateY(-2px);
}

.returned-btn {
    padding: 8px 18px;
    border: none;
    border-radius: 20px;
    cursor: pointer;
    font-size: 13px;
    font-weight: 600;
    transition: all var(--transition);
    background-color: #E53935;
    color: white;
    box-shadow: 0 2px 8px rgba(229, 57, 53, 0.25);
}

.returned-btn:hover {
    background-color: #C62828;
    box-shadow: 0 4px 14px rgba(229, 57, 53, 0.4);
    transform: translateY(-2px);
}

.btn-primary {
    background: #1976D2;
    color: white;
    border: none;
    padding: 9px 20px;
    border-radius: 20px;
    cursor: pointer;
    font-size: 13px;
    font-weight: 600;
    transition: all var(--transition);
    box-shadow: 0 2px 8px rgba(25, 118, 210, 0.25);
    display: inline-flex;
    align-items: center;
    gap: 6px;
}

.btn-primary:hover {
    background: #1565C0;
    box-shadow: 0 4px 14px rgba(25, 118, 210, 0.4);
    transform: translateY(-2px);
}

.btn-danger {
    background: #E53935;
    color: white;
    border: none;
    padding: 9px 20px;
    border-radius: 20px;
    cursor: pointer;
    font-size: 13px;
    font-weight: 600;
    transition: all var(--transition);
    box-shadow: 0 2px 8px rgba(229, 57, 53, 0.25);
    display: inline-flex;
    align-items: center;
    gap: 6px;
}

.btn-danger:hover {
    background: #C62828;
    box-shadow: 0 4px 14px rgba(229, 57, 53, 0.4);
    transform: translateY(-2px);
}

/* ===== MODAL ===== */
.modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.55);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
    backdrop-filter: blur(3px);
    animation: fadeIn 0.2s ease;
}

@keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
}

.modal {
    background: var(--white);
    padding: 32px 28px;
    border-radius: var(--radius-lg);
    width: 380px;
    max-width: 90vw;
    text-align: center;
    box-shadow: var(--shadow-lg);
    animation: slideUp 0.3s ease;
}

@keyframes slideUp {
    from { transform: translateY(24px); opacity: 0; }
    to { transform: translateY(0); opacity: 1; }
}

.modal h2 {
    font-size: 20px;
    font-weight: 700;
    color: var(--text);
    margin-bottom: 12px;
}

.modal p {
    font-size: 14px;
    color: var(--text-muted);
    margin-bottom: 24px;
    line-height: 1.5;
}

.modal-actions {
    display: flex;
    justify-content: center;
    gap: 12px;
    margin-top: 8px;
}

.btn-cancel {
    padding: 10px 24px;
    border: 2px solid #E0E0E0;
    border-radius: 24px;
    cursor: pointer;
    font-size: 14px;
    font-weight: 600;
    background: var(--white);
    color: var(--text-muted);
    transition: all var(--transition);
}

.btn-cancel:hover {
    background: #F5F5F5;
    border-color: #BDBDBD;
    color: var(--text);
}

.btn-confirm {
    padding: 10px 24px;
    border: none;
    border-radius: 24px;
    cursor: pointer;
    font-size: 14px;
    font-weight: 600;
    background: var(--primary-gradient);
    color: white;
    transition: all var(--transition);
    box-shadow: 0 2px 10px rgba(229, 57, 53, 0.3);
}

.btn-confirm:hover {
    background: linear-gradient(135deg, #C62828, #B71C1C);
    box-shadow: 0 4px 16px rgba(229, 57, 53, 0.45);
    transform: translateY(-1px);
}

/* ===== NOTIFICATION MODAL ===== */
.notification-modal {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.55);
    z-index: 1000;
    display: none;
    justify-content: center;
    align-items: center;
    backdrop-filter: blur(3px);
}

.notification-modal.show {
    display: flex;
    animation: fadeIn 0.2s ease;
}

.modal-content {
    background: var(--white);
    border-radius: var(--radius-lg);
    width: 420px;
    max-width: 92vw;
    max-height: 80vh;
    overflow: hidden;
    box-shadow: var(--shadow-lg);
    animation: slideUp 0.3s ease;
    display: flex;
    flex-direction: column;
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 18px 20px;
    background: #FAFAFA;
    border-bottom: 1px solid var(--border);
}

.modal-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: var(--text);
}

.mark-read-btn {
    background: none;
    border: none;
    color: var(--primary);
    cursor: pointer;
    font-size: 0.85rem;
    font-weight: 600;
    padding: 6px 12px;
    border-radius: 16px;
    transition: all var(--transition);
}

.mark-read-btn:hover {
    background: var(--primary-light);
    text-decoration: none;
}

.modal-body {
    padding: 16px 20px;
    max-height: 60vh;
    overflow-y: auto;
}

.notification-list {
    list-style: none;
    padding: 0;
    margin: 0;
}

.notification-item {
    padding: 12px 16px;
    border-bottom: 1px solid #F5F5F5;
    border-radius: var(--radius-sm);
    transition: background var(--transition);
}

.notification-item:last-child {
    border-bottom: none;
}

.notification-item.unread {
    font-weight: 600;
    background: #FFF8E1;
}

.notification-item:hover {
    background: #F5F5F5;
}

.notification-message {
    margin-bottom: 4px;
    font-size: 13px;
    color: var(--text);
}

.notification-time {
    font-size: 11px;
    color: var(--text-muted);
}

.empty-notice {
    color: var(--text-muted);
    text-align: center;
    padding: 24px;
    font-style: italic;
    font-size: 14px;
}

/* ===== MESSAGES VIEW ===== */
.messages-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.55);
    z-index: 1999;
    display: none;
    backdrop-filter: blur(3px);
}

.messages-overlay.active {
    display: block;
    animation: fadeIn 0.2s ease;
}

.messages-view {
    position: fixed;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 92%;
    max-width: 1100px;
    height: 82vh;
    background: var(--white);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-lg);
    z-index: 2000;
    display: none;
    flex-direction: column;
    overflow: hidden;
    animation: slideUp 0.3s ease;
}

.messages-view.active {
    display: flex;
}

.messages-close {
    position: absolute;
    top: 14px;
    right: 14px;
    background: none;
    border: none;
    font-size: 1.3rem;
    cursor: pointer;
    color: var(--text-muted);
    z-index: 2100;
    padding: 6px;
    border-radius: 50%;
    transition: all var(--transition);
    width: 36px;
    height: 36px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.messages-close:hover {
    color: var(--text);
    background: #F0F0F0;
}

.messages-header {
    padding: 18px 24px;
    background: #FAFAFA;
    border-bottom: 1px solid var(--border);
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.messages-header h2 {
    font-size: 1.1rem;
    font-weight: 700;
    color: var(--text);
    margin: 0;
}

.message-search {
    display: flex;
    align-items: center;
}

.message-search input {
    padding: 8px 14px;
    border: 1px solid var(--border);
    border-radius: 20px 0 0 20px;
    outline: none;
    font-size: 13px;
    transition: border-color var(--transition);
}

.message-search input:focus {
    border-color: var(--primary);
}

.message-search button {
    background: var(--primary);
    color: white;
    border: none;
    border-radius: 0 20px 20px 0;
    padding: 8px 14px;
    cursor: pointer;
    transition: background var(--transition);
}

.message-search button:hover {
    background: var(--primary-dark);
}

.messages-container {
    display: flex;
    flex: 1;
    overflow: hidden;
}

.conversation-list {
    width: 300px;
    min-width: 260px;
    border-right: 1px solid var(--border);
    overflow-y: auto;
    background: #FAFAFA;
}

.conversation-item {
    padding: 14px 16px;
    border-bottom: 1px solid #F0F0F0;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 10px;
    transition: background var(--transition);
    font-size: 13px;
}

.conversation-item:hover {
    background: #F0F0F0;
}

.conversation-item.active {
    background: #E3F2FD;
}

.conversation-item.unread {
    background: #FFF8E1;
}

.conversation-summary {
    flex: 1;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.conversation-summary .user-name {
    font-size: 14px;
    font-weight: 600;
    color: var(--text);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.conversation-summary .message-preview {
    font-size: 12px;
    color: var(--text-muted);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.conversation-time {
    font-size: 11px;
    color: var(--text-muted);
    white-space: nowrap;
    flex-shrink: 0;
}

.user-avatar {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    margin-right: 10px;
    object-fit: cover;
    flex-shrink: 0;
}

.conversation-info {
    flex: 1;
    overflow: hidden;
}

.conversation-info h4 {
    margin: 0 0 4px 0;
    font-size: 14px;
    font-weight: 600;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.conversation-info p {
    margin: 0;
    font-size: 12px;
    color: var(--text-muted);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    display: inline-block;
    width: 10px;
    height: 10px;
    background-color: #ff4757;
    border-radius: 50%;
    margin-left: 10px;
    flex-shrink: 0;
}

.message-detail {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: var(--white);
}

.message-detail .message-header {
    padding: 14px 20px;
    border-bottom: 1px solid var(--border);
    display: flex;
    justify-content: space-between;
    align-items: center;
    background: #FAFAFA;
}

.message-user-info {
    display: flex;
    align-items: center;
    gap: 10px;
}

.message-user-info .user-name {
    margin: 0;
    font-size: 15px;
    font-weight: 600;
    color: var(--text);
}

.message-user-info .user-status {
    font-size: 12px;
    color: var(--text-muted);
}

.message-content {
    flex: 1;
    padding: 20px;
    overflow-y: auto;
    background: var(--white);
}

.message-detail-item {
    margin-bottom: 20px;
    padding: 16px;
    background: #FAFAFA;
    border-radius: var(--radius);
}

.message-detail-item h4 {
    font-size: 14px;
    font-weight: 700;
    color: var(--text);
    margin-bottom: 8px;
}

.message-detail-item p {
    font-size: 13px;
    color: var(--text-muted);
    margin: 4px 0;
    line-height: 1.5;
}

.message-actions {
    margin-top: 16px;
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
}

/* Chat messages */
.message {
    margin-bottom: 14px;
    max-width: 70%;
}

.message.sent {
    margin-left: auto;
    text-align: right;
}

.message.received {
    margin-right: auto;
}

.message-text {
    padding: 10px 16px;
    border-radius: 18px;
    display: inline-block;
    word-wrap: break-word;
    max-width: 100%;
    font-size: 13px;
}

.message.sent .message-text {
    background: var(--primary);
    color: white;
}

.message.received .message-text {
    background: #F0F0F0;
    color: #333;
}

.message-time {
    font-size: 11px;
    color: var(--text-muted);
    margin-top: 4px;
}

/* ===== RESPONSIVE ===== */
@media (max-width: 1024px) {
    .sidebar {
        width: 220px;
        left: 10px;
        top: 10px;
        bottom: 10px;
        padding: 20px 14px;
        border-radius: 20px;
    }

    .main-content {
        margin-left: calc(220px + 20px);
        width: calc(100% - 220px - 20px);
        padding: 20px;
    }

    .cards {
        gap: 14px;
    }

    .card {
        padding: 20px 16px;
    }

    .card p {
        font-size: 44px;
    }

    .tables {
        flex-direction: column;
    }

    .table-container {
        min-width: auto;
    }

    .messages-view {
        width: 96%;
        height: 88vh;
    }

    .conversation-list {
        width: 240px;
        min-width: 200px;
    }
}

@media (max-width: 768px) {
    .sidebar {
        width: 72px;
        left: 8px;
        top: 8px;
        bottom: 8px;
        padding: 16px 8px;
        border-radius: 18px;
    }

    .logo {
        width: 44px;
        height: 44px;
    }

    .sidebar-title {
        display: none;
    }

    .nav-item {
        justify-content: center;
        padding: 12px 8px;
        border-left: none;
    }

    .nav-item i {
        margin-right: 0;
        font-size: 18px;
    }

    .nav-item span,
    .nav-item::after {
        display: none;
    }

    .nav-item.active {
        border-left: none;
        border-radius: 14px;
    }

    .nav-item:hover,
    .nav-item.active {
        border-left: none;
    }

    .main-content {
        margin-left: calc(72px + 16px);
        width: calc(100% - 72px - 16px);
        padding: 14px;
    }

    .cards {
        flex-direction: column;
        gap: 12px;
    }

    .card {
        min-width: auto;
    }

    .card p {
        font-size: 40px;
    }

    .tables {
        flex-direction: column;
    }

    .table-container {
        min-width: auto;
        overflow-x: auto;
    }

    table {
        font-size: 12px;
    }

    th, td {
        padding: 10px 8px;
    }

    .top-bar {
        padding: 12px 16px;
        gap: 4px;
    }

    .logout-btn {
        padding: 8px 16px;
        font-size: 13px;
    }

    .messages-view {
        width: 98%;
        height: 92vh;
        border-radius: var(--radius);
    }

    .messages-container {
        flex-direction: column;
    }

    .conversation-list {
        width: 100%;
        max-height: 180px;
        border-right: none;
        border-bottom: 1px solid var(--border);
    }

    .message-search {
        width: 180px;
    }

    .modal {
        width: 92vw;
        padding: 24px 20px;
    }
}

