+/* Import Fonts */
+@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700&family=Inter:wght@300;400;500;600;700&display=swap');
+
+/* ===== CSS VARIABLES ===== */
+:root {
+    --primary: #E53935;
+    --primary-dark: #C62828;
+    --primary-light: #FFEBEE;
+    --primary-gradient: linear-gradient(135deg, #E53935, #C62828);
+    --sidebar-width: 260px;
+    --sidebar-collapsed: 0px;
+    --bg: #F5F6FA;
+    --white: #FFFFFF;
+    --text: #2D3436;
+    --text-muted: #636E72;
+    --border: #E0E0E0;
+    --shadow-sm: 0 2px 8px rgba(0, 0, 0, 0.06);
+    --shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
+    --shadow-lg: 0 12px 40px rgba(0, 0, 0, 0.12);
+    --radius-sm: 8px;
+    --radius: 12px;
+    --radius-lg: 16px;
+    --radius-xl: 24px;
+    --transition: 0.3s cubic-bezier(0.4, 0, 0.2, 1);
+}
+
+/* ===== RESET ===== */
+* {
+    margin: 0;
+    padding: 0;
+    box-sizing: border-box;
+    font-family: 'Poppins', 'Inter', sans-serif;
+}
+
+body {
+    display: flex;
+    min-height: 100vh;
+    width: 100%;
+    justify-content: flex-start;
+    align-items: flex-start;
+    background: var(--bg);
+    overflow-x: hidden;
+}
+
+.background {
+    position: fixed;
+    top: 0;
+    left: 0;
+    width: 100%;
+    height: 100%;
+    background: linear-gradient(135deg, #f5f6fa 0%, #e8eaf6 50%, #fce4ec 100%);
+    z-index: -2;
+}
+
+/* ===== SIDEBAR ===== */
+.sidebar {
+    width: var(--sidebar-width);
+    height: 100vh;
+    background: var(--white);
+    padding: 28px 18px;
+    position: fixed;
+    left: 16px;
+    top: 16px;
+    bottom: 16px;
+    display: flex;
+    flex-direction: column;
+    align-items: center;
+    border-radius: var(--radius-xl);
+    box-shadow: var(--shadow-lg);
+    z-index: 100;
+    transition: all var(--transition);
+    overflow-y: auto;
+}
+
+.logo {
+    width: 72px;
+    height: 72px;
+    margin-bottom: 8px;
+    object-fit: contain;
+    border-radius: 50%;
+    transition: transform var(--transition);
+}
+
+.logo:hover {
+    transform: scale(1.08);
+}
+
+.sidebar-title {
+    color: var(--primary);
+    font-size: 18px;
+    font-weight: 700;
+    margin-bottom: 28px;
+    letter-spacing: 1px;
+    text-transform: uppercase;
+    text-align: center;
+}
+
+.nav-links {
+    list-style: none;
+    padding: 0;
+    width: 100%;
+    display: flex;
+    flex-direction: column;
+    gap: 4px;
+}
+
+.nav-item {
+    display: flex;
+    align-items: center;
+    padding: 12px 16px;
+    font-size: 14px;
+    font-weight: 500;
+    color: var(--text-muted);
+    border-radius: var(--radius);
+    cursor: pointer;
+    transition: all var(--transition);
+    border-left: 3px solid transparent;
+    position: relative;
+}
+
+.nav-item i {
+    margin-right: 12px;
+    font-size: 16px;
+    width: 20px;
+    text-align: center;
+    transition: color var(--transition);
+}
+
+.nav-item:hover {
+    background: #F5F5F5;
+    color: var(--text);
+    border-left: 3px solid #E0E0E0;
+}
+
+.nav-item.active {
+    background: var(--primary-light);
+    color: var(--primary);
+    border-left: 3px solid var(--primary);
+    font-weight: 600;
+    box-shadow: inset 0 0 0 1px rgba(229, 57, 53, 0.1);
+}
+
+.nav-item.active i {
+    color: var(--primary);
+}
+
+/* ===== MAIN CONTENT ===== */
+.main-content {
+    margin-left: calc(var(--sidebar-width) + 32px);
+    padding: 24px 32px;
+    width: calc(100% - var(--sidebar-width) - 32px);
+    min-height: 100vh;
+    background: transparent;
+    transition: margin-left var(--transition), width var(--transition);
+}
+
+/* ===== TOP BAR ===== */
+.top-bar {
+    display: flex;
+    justify-content: flex-end;
+    align-items: center;
+    padding: 16px 24px;
+    background: var(--white);
+    border-radius: var(--radius-lg);
+    box-shadow: var(--shadow-sm);
+    margin-bottom: 24px;
+    gap: 8px;
+    flex-wrap: wrap;
+}
+
+/* ===== NOTIFICATION BUTTON ===== */
+.notif-btn {
+    position: relative;
+    background: #F5F5F5;
+    border: none;
+    font-size: 1.1rem;
+    color: var(--text);
+    cursor: pointer;
+    padding: 10px 14px;
+    margin-right: 4px;
+    border-radius: var(--radius);
+    transition: all var(--transition);
+    display: flex;
+    align-items: center;
+    justify-content: center;
+}
+
+.notif-btn:hover {
+    background: #EEEEEE;
+    color: var(--primary);
+}
+
+.notification-count {
+    position: absolute;
+    top: -4px;
+    right: -4px;
+    background: var(--primary);
+    color: white;
+    border-radius: 50%;
+    width: 20px;
+    height: 20px;
+    display: flex;
+    justify-content: center;
+    align-items: center;
+    font-size: 0.65rem;
+    font-weight: 700;
+    box-shadow: 0 2px 6px rgba(229, 57, 53, 0.3);
+}
+
+.notification-count.hidden {
+    display: none;
+}
+
+/* ===== MESSAGE BUTTON ===== */
+.message-btn {
+    background: #F5F5F5;
+    border: none;
+    color: var(--text);
+    font-size: 1.1rem;
+    cursor: pointer;
+    position: relative;
+    margin-right: 4px;
+    padding: 10px 14px;
+    border-radius: var(--radius);
+    transition: all var(--transition);
+    display: flex;
+    align-items: center;
+    justify-content: center;
+}
+
+.message-btn:hover {
+    background: #EEEEEE;
+    color: var(--primary);
+}
+
+.message-count {
+    position: absolute;
+    top: -4px;
+    right: -4px;
+    background-color: #ff4757;
+    color: white;
+    border-radius: 50%;
+    width: 20px;
+    height: 20px;
+    font-size: 0.65rem;
+    font-weight: 700;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    box-shadow: 0 2px 6px rgba(255, 71, 87, 0.3);
+}
+
+/* ===== LOGOUT BUTTON ===== */
+.logout-btn {
+    background: var(--primary);
+    border: none;
+    font-size: 14px;
+    font-weight: 600;
+    cursor: pointer;
+    margin-left: 12px;
+    padding: 10px 22px;
+    border-radius: var(--radius);
+    color: var(--white);
+    transition: all var(--transition);
+    box-shadow: 0 2px 8px rgba(229, 57, 53, 0.25);
+}
+
+.logout-btn:hover {
+    background: var(--primary-dark);
+    box-shadow: 0 4px 16px rgba(229, 57, 53, 0.35);
+    transform: translateY(-1px);
+}
+
+/* ===== STAT CARDS ===== */
+.cards {
+    display: flex;
+    gap: 20px;
+    margin-bottom: 28px;
+    flex-wrap: wrap;
+}
+
+.card {
+    flex: 1;
+    min-width: 200px;
+    background: var(--white);
+    padding: 28px 24px;
+    box-shadow: var(--shadow);
+    text-align: center;
+    border-radius: var(--radius-lg);
+    transition: all var(--transition);
+    cursor: default;
+    position: relative;
+    overflow: hidden;
+}
+
+.card::before {
+    content: '';
+    position: absolute;
+    top: 0;
+    left: 0;
+    width: 100%;
