/* Import Font */
@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;600&display=swap');

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
    font-family: 'Poppins', sans-serif;
}

body {
    display: flex;
    height: 100%;
    width: 100%;
    justify-content: center;
    align-items: center;
    background: url('bg3.jpg') no-repeat center center/cover;
    overflow: hidden; /* Prevent scrolling issues */
}
.background {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: inherit;
    z-index: -2; /* Background layer */
}
/* Sidebar Styling */
.sidebar {
    width: 250px;
    height: 100vh;
    background: hsl(0, 100%, 97%); /* Dark background */
    padding: 20px;
    position: fixed;
    left: 0;
    top: 0;
    display: flex;
    flex-direction: column;
    align-items: center;
}

.logo {
    width: 100px;
    margin-bottom: 15px;
}

.sidebar-title {
    color: rgb(0, 0, 0);
    font-size: 20px;
    font-weight: bold;
    margin-bottom: 20px;
}

.nav-links {
    list-style: none;
    padding: 0;
    width: 100%;
}

.nav-item {
    display: flex;
    align-items: center; /* Align icon and text */
    padding: 10px 15px;
    font-size: 16px;
    transition: 0.3s;
}

.nav-item i {
    margin-right: 10px; /* Space between icon and text */
    font-size: 18px;
}


.nav-item:hover, .nav-item.active {
    background: rgb(255, 184, 184);
    border-left: 4px solid rgb(255, 52, 52);
    padding-left: 11px;
    font-weight: bold;
    border-radius: 8px; /* Adds rounded corners */
}
.main-content {
    margin-left: 250px;
    padding: 20px;
    width: 100%;
}

/* Top Bar */
.top-bar {
    display: flex;
    justify-content: flex-end;
    padding: 10px;
}

.notif-btn, .logout-btn {
    background: none;
    border: none;
    font-size: 18px;
    cursor: pointer;
    margin-left: 15px;
}


/* Bookings Page Styling */
.bookings-container {
    margin-left: 260px; /* To match sidebar */
    padding: 20px;
}

/* Sorting Buttons */
.sort-buttons {
    display: flex;
    gap: 10px;
    margin-bottom: 15px;
}

.sort-buttons button {
    padding: 8px 12px;
    border: none;
    background: #ff3434;
    color: white;
    cursor: pointer;
    border-radius: 5px;
    transition: 0.3s;
}

.sort-buttons button:hover {
    background: #d63030;
}

/* Table Styling */
.bookings-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 20px;
    background: white;
    border-radius: 8px;
    overflow: hidden;
}

.bookings-table th, .bookings-table td {
    padding: 12px;
    border-bottom: 1px solid #ddd;
    text-align: left;
}

.bookings-table th {
    background: #ff3434;
    color: white;
}

.no-data {
    text-align: center;
    font-weight: bold;
    color: #555;
}

/* Responsive */
@media (max-width: 768px) {
    .bookings-table {
        font-size: 14px;
    }
}

import { database } from "./firebase-config.js";
import { ref, get } from "https://www.gstatic.com/firebasejs/10.7.1/firebase-database.js";

// Fetch and display bookings with billing information
async function fetchAndDisplayBookings() {
    try {
        // Fetch bookings and bills in parallel
        const [bookingsSnapshot, billsSnapshot] = await Promise.all([
            get(ref(database, 'bookings_history')),
            get(ref(database, 'Bills'))
        ]);

        const tableBody = document.getElementById('bookingsTableBody');
        tableBody.innerHTML = ''; // Clear loading message

        if (!bookingsSnapshot.exists()) {
            tableBody.innerHTML = `
                <tr>
                    <td colspan="6" class="no-data">No bookings found</td>
                </tr>
            `;
            return;
        }

        // Create a map of bills by userId for quick lookup
        const billsMap = {};
        if (billsSnapshot.exists()) {
            billsSnapshot.forEach(billSnapshot => {
                const bill = billSnapshot.val();
                billsMap[bill.userId] = {
                    finalFee: bill.finalFee || '0',
                    timestamp: bill.timestamp || ''
                };
            });
        }

        const bookings = [];
        bookingsSnapshot.forEach((childSnapshot) => {
            const booking = childSnapshot.val();
            const userBill = billsMap[booking.userId] || {};
            
            bookings.push({
                id: childSnapshot.key,
                name: booking.fullName || 'Unknown',
                car: booking.car?.carName || 'Unknown',
                price: booking.car?.rentalPrice || '0',
                date: booking.bookingDate || 'Unknown date',
                destination: booking.toLocation || 'Not specified',
                finalFee: userBill.finalFee || 'Not billed yet',
                userId: booking.userId
            });
        });

        // Sort by date (newest first)
        bookings.sort((a, b) => new Date(b.date) - new Date(a.date));

        // Display bookings in table
        bookings.forEach(booking => {
            const row = document.createElement('tr');
            row.innerHTML = `
                <td>${booking.name}</td>
                <td>${booking.car}</td>
                <td>₱${booking.price}</td>
                <td>${formatDate(booking.date)}</td>
                <td>${booking.destination}</td>
                <td>${booking.finalFee === 'Not billed yet' ? 
                    booking.finalFee : 
                    `₱${booking.finalFee}`}</td>
            `;
            tableBody.appendChild(row);
        });

    } catch (error) {
        console.error("Error fetching bookings:", error);
        document.getElementById('bookingsTableBody').innerHTML = `
            <tr>
                <td colspan="6" class="no-data">Error loading bookings</td>
            </tr>
        `;
    }
}

// Format date to readable format
function formatDate(dateString) {
    if (!dateString) return 'Unknown date';
    
    try {
        const date = new Date(dateString);
        return date.toLocaleDateString('en-US', {
            year: 'numeric',
            month: 'short',
            day: 'numeric'
        });
    } catch (e) {
        return dateString;
    }
}

// Initialize the page
document.addEventListener('DOMContentLoaded', () => {
    // Set active navigation
    document.getElementById('bookings').classList.add('active');
    
    // Fetch and display bookings
    fetchAndDisplayBookings();
    
    // Navigation event listeners
    document.getElementById('dashboard').addEventListener('click', () => {
        window.location.href = 'dashboard.html';
    });
    
    document.getElementById('track-cars').addEventListener('click', () => {
        window.location.href = 'track-cars.html';
    });
    
    document.getElementById('cars').addEventListener('click', () => {
        window.location.href = 'cars.html';
    });

    document.getElementById('users').addEventListener('click', () => {
        window.location.href = 'users.html';
    });
    document.getElementById('settings').addEventListener('click', () => {
        window.location.href = 'settings.html';
    });
});

